SourceCode.Declaration:
/// <summary>
/// Custom service exposing note header lookup operations.
/// </summary>
class ConDemoNoteLookupService
{
}

Method.Source:
/// <summary>
/// Returns the subject of a note header identified by its note ID.
/// </summary>
/// <param name = "_request">The lookup request holding the note ID.</param>
/// <returns>A response contract holding the subject of the note header.</returns>
public ConDemoNoteLookupResponse lookup(ConDemoNoteLookupRequest _request)
{
    ConDemoNoteLookupResponse  response = new ConDemoNoteLookupResponse();
    ConDemoNoteHeader          noteHeader;
    Num                        noteId = _request.parmNoteId();

    select firstonly Subject from noteHeader
    where noteHeader.NoteId == noteId;

    response.parmSubject(noteHeader.Subject);

    return response;
}
